-- technical_sport_drills + lifestyle_protocols — DDL + seed (DB-first, fallback statico
-- TEAM_SPORT_DRILL_LIBRARY / LIFESTYLE_PROTOCOL_LIBRARY). anon SELECT, service_role write.
-- Loader client: lib/training/libraries-client.ts. Idempotente (ON CONFLICT).

create table if not exists public.technical_sport_drills (
  id text primary key, sport text not null, sort_order integer not null default 0,
  data jsonb not null, updated_at timestamptz not null default now()
);
create index if not exists technical_sport_drills_sport_idx on public.technical_sport_drills (sport);
create index if not exists technical_sport_drills_sort_idx on public.technical_sport_drills (sort_order);
alter table public.technical_sport_drills enable row level security;

create table if not exists public.lifestyle_protocols (
  id text primary key, sport text not null, sort_order integer not null default 0,
  data jsonb not null, updated_at timestamptz not null default now()
);
create index if not exists lifestyle_protocols_sport_idx on public.lifestyle_protocols (sport);
create index if not exists lifestyle_protocols_sort_idx on public.lifestyle_protocols (sort_order);
alter table public.lifestyle_protocols enable row level security;

do $policy$
begin
  if not exists (select 1 from pg_policies where schemaname='public' and tablename='technical_sport_drills' and policyname='technical_sport_drills_read_anon') then
    create policy technical_sport_drills_read_anon on public.technical_sport_drills for select to anon, authenticated using (true); end if;
  if not exists (select 1 from pg_policies where schemaname='public' and tablename='technical_sport_drills' and policyname='technical_sport_drills_write_service') then
    create policy technical_sport_drills_write_service on public.technical_sport_drills for all to service_role using (true) with check (true); end if;
  if not exists (select 1 from pg_policies where schemaname='public' and tablename='lifestyle_protocols' and policyname='lifestyle_protocols_read_anon') then
    create policy lifestyle_protocols_read_anon on public.lifestyle_protocols for select to anon, authenticated using (true); end if;
  if not exists (select 1 from pg_policies where schemaname='public' and tablename='lifestyle_protocols' and policyname='lifestyle_protocols_write_service') then
    create policy lifestyle_protocols_write_service on public.lifestyle_protocols for all to service_role using (true) with check (true); end if;
end
$policy$;

insert into public.technical_sport_drills (id, sport, sort_order, data)
select e->>'id', e->>'sport', (ord-1)::int, e
from jsonb_array_elements($drills$
